include("shared.lua")if Pets.EnableDynamicLights then 	function ENT:Think()	  	self.BaseClass.Think(self)		if !IsValid(self.dlight) then			self.dlight = DynamicLight(self:EntIndex())		end		local dlight = self.dlight		dlight.Pos = self:GetPos() + self:GetAngles():Forward() * 25		dlight.r = 255		dlight.g = 255		dlight.b = 255		dlight.Brightness = 1		dlight.MinLight = 0.15		dlight.Size = 92		dlight.Dir = self:GetAngles():Forward() * 10		dlight.InnerAngle = 45		dlight.OuterAngle = 50		dlight.Decay = 0		dlight.DieTime = CurTime() + 0.5		dlight.Style = 1	end end